import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Profile() {
    const navigate = useNavigate();
    const { user, updateProfile, logout, logoutLoading } = useAuth();
    const [formData, setFormData] = useState({
        name: user?.name || '',
        phone: user?.phone || '',
        address: user?.address || '',
        city: user?.city || '',
        region: user?.region || '',
        postal_code: user?.postal_code || '',
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData((prev) => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setSuccess('');

        try {
            await updateProfile(formData);
            setSuccess('Profile updated successfully!');
            setTimeout(() => setSuccess(''), 3000);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to update profile');
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        if (logoutLoading) {
            return;
        }

        if (window.confirm('Are you sure you want to logout?')) {
            try {
                await logout();
                navigate('/');
            } catch {
                navigate('/');
            }
        }
    };

    return (
        <div className="profile-page">
            <div className="container">
                <div className="profile-header">
                    <img
                        src="/images/Robots-automobile-assembly-line-Russia.webp?v=20260401"
                        alt="Profile"
                        className="profile-page-avatar"
                    />
                    <h1>My Profile</h1>
                    <p>Manage your account information</p>

                    <div className="profile-stats">
                        <div className="profile-stat">
                            <span className="profile-stat__label">Account Type</span>
                            <span className="profile-stat__value">
                                {user?.role ? user.role.charAt(0).toUpperCase() + user.role.slice(1) : 'Customer'}
                            </span>
                        </div>
                        <div className="profile-stat">
                            <span className="profile-stat__label">Member Since</span>
                            <span className="profile-stat__value">
                                {user?.created_at ? new Date(user.created_at).toLocaleDateString() : 'N/A'}
                            </span>
                        </div>
                        <div className="profile-stat">
                            <span className="profile-stat__label">Status</span>
                            <span className="profile-stat__value">Active</span>
                        </div>
                    </div>
                </div>

                <div className="profile-container">
                    <div className="profile-card">
                        <div className="profile-content">
                            {error && <div className="alert alert-danger">{error}</div>}
                            {success && <div className="alert alert-success">{success}</div>}

                            <form onSubmit={handleSubmit} className="profile-form">
                                <section className="form-section">
                                    <h2>Personal Information</h2>

                                    <div className="form-group">
                                        <label htmlFor="name">Full Name</label>
                                        <input
                                            type="text"
                                            id="name"
                                            name="name"
                                            value={formData.name}
                                            onChange={handleChange}
                                            required
                                            disabled={loading}
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label htmlFor="phone">Phone Number</label>
                                        <input
                                            type="tel"
                                            id="phone"
                                            name="phone"
                                            value={formData.phone}
                                            onChange={handleChange}
                                            disabled={loading}
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label htmlFor="email">Email Address (Read-only)</label>
                                        <input
                                            type="email"
                                            id="email"
                                            value={user?.email}
                                            disabled
                                        />
                                    </div>

                                    <div className="form-group">
                                        <label htmlFor="role">Account Type</label>
                                        <input
                                            type="text"
                                            id="role"
                                            value={user?.role ? user.role.charAt(0).toUpperCase() + user.role.slice(1) : ''}
                                            disabled
                                        />
                                    </div>
                                </section>

                                <section className="form-section">
                                    <h2>Address Information</h2>

                                    <div className="form-group">
                                        <label htmlFor="address">Street Address</label>
                                        <input
                                            type="text"
                                            id="address"
                                            name="address"
                                            value={formData.address}
                                            onChange={handleChange}
                                            disabled={loading}
                                        />
                                    </div>

                                    <div className="form-row">
                                        <div className="form-group">
                                            <label htmlFor="city">City</label>
                                            <input
                                                type="text"
                                                id="city"
                                                name="city"
                                                value={formData.city}
                                                onChange={handleChange}
                                                disabled={loading}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label htmlFor="region">Region</label>
                                            <input
                                                type="text"
                                                id="region"
                                                name="region"
                                                value={formData.region}
                                                onChange={handleChange}
                                                disabled={loading}
                                            />
                                        </div>

                                        <div className="form-group">
                                            <label htmlFor="postal_code">Postal Code</label>
                                            <input
                                                type="text"
                                                id="postal_code"
                                                name="postal_code"
                                                value={formData.postal_code}
                                                onChange={handleChange}
                                                disabled={loading}
                                            />
                                        </div>
                                    </div>
                                </section>

                                <div className="form-actions">
                                    <button
                                        type="submit"
                                        className="btn btn-primary"
                                        disabled={loading}
                                    >
                                        {loading ? 'Saving...' : 'Save Changes'}
                                    </button>
                                </div>
                            </form>
                        </div>
                    </div>

                    <div className="profile-sidebar">
                        <div className="sidebar-card sidebar-card--quick-links">
                            <h3>Quick Actions</h3>
                            <Link to="/dashboard" className="btn btn-primary btn-block">Go to Dashboard</Link>
                            <Link to="/dashboard/orders" className="btn btn-outline-primary btn-block">View Orders</Link>
                        </div>

                        <div className="sidebar-card">
                            <h3>Account Settings</h3>
                            <button
                                onClick={handleLogout}
                                className="btn btn-danger btn-block"
                                disabled={logoutLoading}
                                aria-busy={logoutLoading}
                            >
                                {logoutLoading ? 'Logging out...' : 'Logout'}
                            </button>
                        </div>

                        <div className="sidebar-card">
                            <h3>Account Info</h3>
                            <div className="info-item">
                                <span className="label">Member Since</span>
                                <span className="value">
                                    {user?.created_at ? new Date(user.created_at).toLocaleDateString() : 'N/A'}
                                </span>
                            </div>
                            <div className="info-item">
                                <span className="label">Email</span>
                                <span className="value value--truncate">{user?.email || 'N/A'}</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
